/* Aula 26 — modelJs: save/load + versionamento */

function save(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

function load(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    if (raw === null) return fallback;
    return JSON.parse(raw);
  } catch (err) {
    console.error('load falhou:', err.message);
    return fallback;
  }
}

// 1) Preferências
const prefs = { theme: 'dark', fontSize: 16 };
save('prefs', prefs);
const prefsLidas = load('prefs', { theme: 'light', fontSize: 14 });
console.log('prefsLidas:', prefsLidas);

// 2) Versionamento / migração didática
// v1: data = ['a','b']
save('lista', { version: 1, data: ['a', 'b'] });

function loadListaV2() {
  const payload = load('lista', { version: 2, data: [] });

  // se já for v2, retorna
  if (payload.version === 2) return payload;

  // migrar v1 -> v2
  if (payload.version === 1 && Array.isArray(payload.data)) {
    const migrado = {
      version: 2,
      data: payload.data.map((texto, idx) => ({
        id: Date.now() + idx,
        texto,
        done: false
      }))
    };
    save('lista', migrado);
    return migrado;
  }

  // formato desconhecido
  return { version: 2, data: [] };
}

console.log('lista v2:', loadListaV2());
